const services = [
  {
    badge: "Core Service",
    icon: "👥",
    title: "Recruitment Process Outsourcing",
    description:
      "End-to-end talent acquisition management. We embed into your HR function and own the full hiring lifecycle — from sourcing to onboarding.",
    features: [
      "Full-cycle recruiting",
      "Talent pipeline strategy",
      "ATS management & reporting",
      "Employer brand support",
    ],
    primary: true,
  },
  {
    badge: "Popular",
    icon: "🎧",
    title: "Virtual Assistants",
    description:
      "Pre-vetted, skilled VAs that handle your administrative, research, and operational tasks — freeing your team for high-value work.",
    features: [
      "Executive assistance",
      "Data entry & research",
      "Calendar & inbox management",
      "CRM & operations support",
    ],
    primary: false,
  },
  {
    badge: "New",
    icon: "💻",
    title: "Development",
    description:
      "Custom software, web, and product development delivered by vetted engineers integrated into your team on a sprint-by-sprint basis.",
    features: [
      "Web & mobile development",
      "API integrations",
      "Staff augmentation",
      "QA & testing",
    ],
    primary: false,
  },
];

export default function ServicesGrid() {
  return (
    <section id="services" className="max-w-6xl mx-auto px-6 py-24">
      <div className="mb-12">
        <p className="text-xs font-semibold text-teal-400 uppercase tracking-widest mb-3">
          What we do
        </p>
        <h2 className="text-4xl font-extrabold text-white tracking-tight mb-3">
          Three services.
          <br />
          One growth engine.
        </h2>
        <p className="text-slate-400 text-base max-w-lg">
          Each service is designed to integrate seamlessly with your existing
          workflow and scale with your ambitions.
        </p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
        {services.map((service) => (
          <div
            key={service.title}
            className={`rounded-2xl p-7 border transition-all hover:-translate-y-1 duration-300 ${
              service.primary
                ? "bg-teal-500/[0.06] border-teal-500/40"
                : "bg-white/[0.04] border-teal-500/15 hover:border-teal-500/40"
            }`}
          >
            <span className="inline-block bg-teal-500/10 text-teal-400 text-xs font-semibold uppercase tracking-widest px-2 py-1 rounded mb-4">
              {service.badge}
            </span>
            <div className="text-3xl mb-4">{service.icon}</div>
            <h3 className="text-white font-bold text-lg mb-3">
              {service.title}
            </h3>
            <p className="text-slate-400 text-sm leading-relaxed mb-4">
              {service.description}
            </p>
            <ul className="border-t border-white/[0.06] pt-4 flex flex-col gap-2">
              {service.features.map((f) => (
                <li
                  key={f}
                  className="text-slate-300 text-sm flex items-center gap-2"
                >
                  <span className="text-teal-400 text-xs">→</span>
                  {f}
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </section>
  );
}
